    for(int a=0;a<size[j];a++){

        if(pos[j][a]>pos[i][0]){

            pivot=pos[j][a];

            break;

        }

    }

    if(pivot==-1) return false;

    for(int b=0;b<size[k];b++){

        if(pos[k][b]>pivot){

            return true;

        }

    }

    return false;

}

