        size[i]=0;

    }

    scanf("%d",&n);

    scanf("%s",&s);

    for(int i=0;i<n;i++){

        int num=s[i]-'0';

        pos[num][size[num]]=i;

        size[num]++;

    }

    for(int i=0;i<=9;i++){

        for(int j=0;j<=9;j++){

            for(int k=0;k<=9;k++){

