    if(p==n-2) continue;

    p++;

    while(s[p]!=ss[1]){

      p++;

      if(p==n-1) break;

    }

    if(p==n-1) continue;

    p++;

    while(s[p]!=ss[2]){

      p++;

      if(p==n) break;

    }

    if(p==n) continue;

    ans++;

  }

  cout << ans << '\n';

  return 0;

}

