#include <bits/stdc++.h>

#define REP(i, n) for(int i = 0; i < n; i++)

#define REPR(i, n) for(int i = n; i >= 0; i--)

#define FOR(i, m, n) for(int i = m; i < n; i++)

#define ALL(v) v.begin(), v.end()

using namespace std;

typedef long long ll;

typedef long double ld;

const ll MOD = 1e9 + 7;



int main() {

  ios::sync_with_stdio(false);

  cin.tie(nullptr);

  int n;

  string s;

  cin >> n >> s;

  int ans = 0;

  REP(i,1000){

    stringstream ssub;

    ssub << setw(3) << setfill('0') << i;

    string ss = ssub.str();

    int p = 0;

    while(s[p]!=ss[0]){

      p++;

      if(p==n-2) break;

    }

    if(p==n-2) continue;

    p++;

    while(s[p]!=ss[1]){

      p++;

      if(p==n-1) break;

    }

    if(p==n-1) continue;

    p++;

    while(s[p]!=ss[2]){

      p++;

      if(p==n) break;

    }

    if(p==n) continue;

    ans++;

  }

  cout << ans << '\n';

  return 0;

}

