            already.pop();

            already.push(bP(input.top().a, input.top().b));

        }

        input.pop();

    }

    LL ans = 0;

    while(!already.empty()){

        ans += 1LL * already.top().b;

        already.pop();

    }

    printf("%lld\n", ans);

    return 0;

}

